	private static int getResult(String s) {
		Queue<String> q = new LinkedList<>();
		for(String str : s.split(" ")) {
			if(str.equals(""))
				continue;
			q.offer(str);
		}
		q.offer(" ");
		return helper(q);
	}

	private static int helper(Queue<String> q) {
		int prev = 0, num = 0, sum = 0;
		char op = '+';
		while(!q.isEmpty()) {
			String s = q.poll();
			char c = s.charAt(0);
			if((c >= '0' && c <= '9') || c == '(') {
				if(c >= '0' && c <= '9')
					num = Integer.parseInt(s + "");
				else if(c == '(')
					num = helper(q);
				switch (op) {
					case '+':
	                    sum += prev;
	                    prev = num;
	                    break;

	                case '-':
	                    sum += prev;
	                    prev = -num;
	                    break;

	                case '*':
	                    prev *= num;
	                    break;

	                case '/':
	                    prev /= num;
	                    break;
				}
			}else {
				if(c == ')')
					break;
				op = c;
				if(op == '*' || op == '/')
					prev = 1;
				num = 0;
			}
		}
		return prev + sum;
	}

