static int index = 0;
public static int search(String[] exp)
{
    char op = '$';
    Integer prev = null;
    while (index < exp.length)
    {
        if (isOperator(exp[index])) {
            op = exp[index].charAt(0);
        }
        else if (isOpenBrace(exp[index])) {
            index++;
            int next = search(exp);
            if(prev != null)
                prev = compute(op, prev, next);
            else
                prev = next;
        } else if (isCloseBrace(exp[index])) {
            return prev;
        } else {
            if (prev == null) {
                prev = Integer.parseInt(exp[index]);
            } else {
                prev = compute(op, prev, Integer.parseInt(exp[index]));
            }
        }
        index++;
    }

    return prev;
}

private static boolean isCloseBrace(String s) {
    return s.length() == 1 && s.charAt(0) == ')';
}

private static boolean isOpenBrace(String s) {
    return s.length() == 1 && s.charAt(0) == '(';
}

private static boolean isOperator(String s) {
    return s.length() == 1 && (s.charAt(0) == '*' || s.charAt(0) == '+');
}

private static int compute(Character optr, int op1, int op2) {
    if (optr == '+')
        return op1 + op2;
    else
        return op1 * op2;
}

