func mult(l, r int) int {
	return l * r
}

func add(l, r int) int {
	return l + r
}

func evaluate(expression string) int {
	// keep adding to top of stack until we find ")"
	// Pop till "(" and solve popped equation
	// add result to top of stack
	exps := strings.Split(expression, " ")
	stack := make([]string, 0, len(exps))

	for _, expression := range exps {
		if expression != ")" {
			stack = append(stack, expression)
		} else {
			i := len(stack) - 1
			for stack[i] != "(" {
				i--
			}
			r := solve(stack[i+1:])
			//[ "+", "1", "2" ]
			stack = stack[0:i]
			stack = append(stack, r)
		}
	}

	var result string
	if len(stack) > 1 {
		result = solve(stack)
	} else {
		result = stack[0]
	}

	val, _ := strconv.Atoi(result)
	return val
}

func solve(s []string) string {
	op := s[0]
	if op != "*" && op != "+" {
		val, _ := strconv.Atoi(strings.Join(s, ""))
		return strconv.Itoa(val)
	}

	result := 0
	operation := add
	if op == "*" {
		result = 1
		operation = mult
	}

	for i := 1; i < len(s); i++ {
		val, _ := strconv.Atoi(s[i])
		result = operation(result, val)
	}
	return strconv.Itoa(result)
}
