```
public class Solution {

    public static int evaluate(String expression) {
        String[] tokens = expression.split(" ");
        // precalculate all matching  parentheses and cache them
        Map<Integer, Integer> openToMatchingClosingParenMap = getMatchingParens(tokens);
        return evaluateHelper(tokens, 0, tokens.length - 1, openToMatchingClosingParenMap);
    }

    private static int evaluateHelper(String[] tokens, int start, int end, Map<Integer, Integer> parensMap) {
        String token = tokens[start];

        if (token.equals("(")) {
            // evaluate subexpression between opening "(" and matching ")"
            int matchingEndParen = parensMap.get(start);
            return evaluateHelper(tokens, start + 1, matchingEndParen - 1, parensMap);
        } else if (token.equals("+")) {
            int additionResult = 0;

            for (int i = start + 1; i <= end; i++) {
                if (tokens[i].equals("(")) {
                    // one of the operands of this addition chain is a subexpression so evaluate it recursively
                    int matchingEndParen = parensMap.get(i);
                    additionResult += evaluateHelper(tokens, i + 1, matchingEndParen - 1, parensMap);
                    i = matchingEndParen; // subexpression was already evaluated so skip those tokens
                } else {
                    additionResult += evaluateHelper(tokens, i, end, parensMap);
                }
            }

            return additionResult;
        } else if (token.equals("*")) {
            int multiplicationResult = 1;
            for (int i = start + 1; i <= end; i++) {
                if (tokens[i].equals("(")) {
                    // one of the operands of this multiplication chain is a subexpression so evaluate it recursively
                    int matchingEndParen = parensMap.get(i);
                    multiplicationResult *= evaluateHelper(tokens, i + 1, matchingEndParen - 1, parensMap);
                    i = matchingEndParen; // subexpression was already evaluated so skip those tokens
                } else {
                    multiplicationResult *= evaluateHelper(tokens, i, end, parensMap);
                }
            }
            return multiplicationResult;
        } else if (token.equals(")")) {
            // skip ")"
            return evaluateHelper(tokens, start + 1, end, parensMap);
        } else {
            // not an operator, and not a parentheses so it must be an operand
            return Integer.parseInt(token);
        }
    }

    private static Map<Integer, Integer> getMatchingParens(String[] tokens) {
        Map<Integer, Integer> parensMap = new HashMap<>();

        for (int i = 0; i < tokens.length; i++) {
            if (tokens[i].equals("(")) {
                parensMap.put(i, findMatchingParen(tokens, i));
            }
        }

        return parensMap;
    }

    private static int findMatchingParen(String[] tokens, int startIndex) {
        int openParensCount = 1;

        for (int i = startIndex + 1; i < tokens.length; i++) {
            if (tokens[i].equals("(")) {
                openParensCount++;
            } else if (tokens[i].equals(")")) {
                openParensCount--;
            }

            if (openParensCount == 0) {
                return i;
            }
        }

        return -1;
    }
}
